  1→import React, {useState} from 'react';
  2→import {Pressable, StyleSheet, Text, View} from 'react-native';
  3→import {useTheme} from '../../theme/ThemeProvider';
  4→import {fonts} from '../../theme/typography';
  5→import {spacing} from '../../theme/spacing';
  6→import {HeartIcon, CommentIcon, BookmarkIcon, RepostIcon} from '../icons';
  7→import {getReactionEmoji} from '../../lib/reactions';
  8→import {ReactionPicker} from './ReactionPicker';
  9→
 10→interface ActionBarProps {
 11→  likeCount: number;
 12→  commentCount: number;
 13→  bookmarkCount?: number;
 14→  isLiked?: boolean;
 15→  isBookmarked?: boolean;
 16→  userReaction?: string | null;
 17→  onLike?: () => void;
 18→  onComment?: () => void;
 19→  onBookmark?: () => void;
 20→  onRepost?: () => void;
 21→  onReact?: (type: string) => void;
 22→}
 23→
 24→export function ActionBar({
 25→  likeCount,
 26→  commentCount,
 27→  bookmarkCount,
 28→  isLiked,
 29→  isBookmarked,
 30→  userReaction,
 31→  onLike,
 32→  onComment,
 33→  onBookmark,
 34→  onRepost,
 35→  onReact,
 36→}: ActionBarProps) {
 37→  const {colors} = useTheme();
 38→  const [pickerOpen, setPickerOpen] = useState(false);
 39→
 40→  const reactionEmoji = getReactionEmoji(userReaction);
 41→  const hasReaction = !!userReaction;
 42→
 43→  const handleQuickTap = () => {
 44→    if (onReact) {
 45→      if (hasReaction) {
 46→        // Remove current reaction
 47→        onReact(userReaction!);
 48→      } else {
 49→        // Default to heart
 50→        onReact('heart');
 51→      }
 52→    } else {
 53→      onLike?.();
 54→    }
 55→  };
 56→
 57→  const handleLongPress = () => {
 58→    if (onReact) {
 59→      setPickerOpen(true);
 60→    }
 61→  };
 62→
 63→  const handlePickerSelect = (type: string) => {
 64→    setPickerOpen(false);
 65→    onReact?.(type);
 66→  };
 67→
 68→  return (
 69→    <View style={styles.container}>
 70→      <ReactionPicker
 71→        visible={pickerOpen}
 72→        currentReaction={userReaction}
 73→        onSelect={handlePickerSelect}
 74→        onClose={() => setPickerOpen(false)}
 75→      />
 76→
 77→      <View style={[styles.bar, {borderTopColor: colors.borderCard}]}>
 78→        <Pressable
 79→          style={styles.action}
 80→          onPress={handleQuickTap}
 81→          onLongPress={handleLongPress}
 82→          delayLongPress={400}
 83→          hitSlop={8}>
 84→          {reactionEmoji ? (
 85→            <Text style={styles.reactionEmoji}>{reactionEmoji}</Text>
 86→          ) : (
 87→            <HeartIcon
 88→              size={18}
 89→              color={isLiked ? colors.danger : colors.iconDefault}
 90→              filled={isLiked}
 91→            />
 92→          )}
 93→          {likeCount > 0 && (
 94→            <Text
 95→              style={[
 96→                styles.count,
 97→                {color: hasReaction || isLiked ? colors.danger : colors.textMuted},
 98→              ]}>
 99→              {likeCount}
100→            </Text>
101→          )}
102→        </Pressable>
103→
104→        <Pressable style={styles.action} onPress={onComment} hitSlop={8}>
105→          <CommentIcon size={18} color={colors.iconDefault} />
106→          {commentCount > 0 && (
107→            <Text style={[styles.count, {color: colors.textMuted}]}>
108→              {commentCount}
109→            </Text>
110→          )}
111→        </Pressable>
112→
113→        <Pressable style={styles.action} onPress={onBookmark} hitSlop={8}>
114→          <BookmarkIcon
115→            size={18}
116→            color={isBookmarked ? colors.accentAmber : colors.iconDefault}
117→            filled={isBookmarked}
118→          />
119→          {(bookmarkCount ?? 0) > 0 && (
120→            <Text
121→              style={[
122→                styles.count,
123→                {color: isBookmarked ? colors.accentAmber : colors.textMuted},
124→              ]}>
125→              {bookmarkCount}
126→            </Text>
127→          )}
128→        </Pressable>
129→
130→        <Pressable style={styles.action} onPress={onRepost} hitSlop={8}>
131→          <RepostIcon size={18} color={colors.iconDefault} />
132→        </Pressable>
133→      </View>
134→    </View>
135→  );
136→}
137→
138→const styles = StyleSheet.create({
139→  container: {
140→    position: 'relative',
141→  },
142→  bar: {
143→    flexDirection: 'row',
144→    alignItems: 'center',
145→    paddingHorizontal: spacing.lg,
146→    paddingVertical: spacing.md,
147→    borderTopWidth: StyleSheet.hairlineWidth,
148→    gap: spacing.xl,
149→  },
150→  action: {
151→    flexDirection: 'row',
152→    alignItems: 'center',
153→    gap: spacing.xs,
154→  },
155→  count: {
156→    fontSize: 13,
157→    fontFamily: fonts.ui.medium,
158→  },
159→  reactionEmoji: {
160→    fontSize: 18,
161→    lineHeight: 22,
162→  },
163→});
